{"id":"go:commands/hugobuilder.go#rebuildSitesForChanges@1150","source":"func (c *hugoBuilder) rebuildSitesForChanges(ids []identity.Identity) (err error) {
	defer func() {
		c.errState.setBuildErr(err)
	}()

	var h *hugolib.HugoSites
	h, err = c.hugo()
	if err != nil {
		return
	}
	whatChanged := &hugolib.WhatChanged{}
	whatChanged.Add(ids...)
	err = h.Build(hugolib.BuildCfg{NoBuildLock: true, WhatChanged: whatChanged, RecentlyTouched: c.visitedURLs, ErrRecovery: c.errState.wasErr()})

	return
}"}

